// ❌ BAD - assuming struct assignment shares state like a class
struct CartItem { public int Quantity; }
CartItem original = new CartItem { Quantity = 3 };
CartItem discount = original;
discount.Quantity = 1;
Console.WriteLine(original.Quantity); // developer expects 1 but gets 3

// ✅ GOOD - correct mental model: struct copy is independent
CartItem a = new CartItem { Quantity = 3 };
CartItem b = a;
b.Quantity = 1;
Console.WriteLine(a.Quantity); // 3 - unchanged
Console.WriteLine(b.Quantity); // 1 - only b changed

// ❌ BAD - editing a copied reference thinking it is an independent object
class Order { public decimal Total; }
Order invoice = new Order { Total = 100m };
Order draft = invoice; // copies only the reference
draft.Total = 0m;      // wipes the shared object
Console.WriteLine(invoice.Total); // 0 - original destroyed

// ✅ GOOD - explicit copy when independence is required
Order invoice2 = new Order { Total = 100m };
Order draft2 = new Order { Total = invoice2.Total }; // new object
draft2.Total = 0m;
Console.WriteLine(invoice2.Total); // 100 - original safe

// ❌ BAD - virtual call in constructor crashes when derived field is null
class PaymentProcessor {
    public PaymentProcessor() { Validate(); }
    public virtual void Validate() => Console.WriteLine("base ok");
}
class StripeProcessor : PaymentProcessor {
    private string _apiKey;
    public StripeProcessor() { _apiKey = "sk_live_xxx"; }
    public override void Validate() => Console.WriteLine(_apiKey.Length); // NRE
}

// ✅ GOOD - call Initialize after construction is complete
class StripeProcessor2 : PaymentProcessor {
    private string _apiKey = "sk_live_xxx";
    public override void Validate() => Console.WriteLine(_apiKey.Length); // safe
}

// ❌ BAD - non-virtual method, polymorphism does not work through base reference
class Notification { public void Send() => Console.WriteLine("base send"); }
class EmailNotification : Notification { public void Send() => Console.WriteLine("email"); }

Notification n = new EmailNotification();
n.Send(); // prints 'base send' - NOT 'email'

// ✅ GOOD - virtual + override enables polymorphic dispatch
class Notification2 { public virtual void Send() => Console.WriteLine("base send"); }
class EmailNotification2 : Notification2 { public override void Send() => Console.WriteLine("email"); }

Notification2 n2 = new EmailNotification2();
n2.Send(); // prints 'email' - runtime type is used

// ❌ BAD - new hides, causing surprising output through a base reference
class Report { public virtual void Generate() => Console.WriteLine("base report"); }
class SalesReport : Report { public new void Generate() => Console.WriteLine("sales"); }

Report r = new SalesReport();
r.Generate(); // prints 'base report' - not 'sales'

// ✅ GOOD - override for true polymorphism
class Report2 { public virtual void Generate() => Console.WriteLine("base report"); }
class SalesReport2 : Report2 { public override void Generate() => Console.WriteLine("sales"); }

Report2 r2 = new SalesReport2();
r2.Generate(); // prints 'sales' - correct

// ❌ BAD - hiding a property with new returns the wrong value through a base reference
class UserAccount { public string Role { get; set; } = "viewer"; }
class AdminAccount : UserAccount { public new string Role { get; set; } = "admin"; }

UserAccount u = new AdminAccount();
Console.WriteLine(u.Role); // prints 'viewer' - security risk

// ✅ GOOD - virtual+override for correct polymorphic property
class UserAccount2 { public virtual string Role { get; set; } = "viewer"; }
class AdminAccount2 : UserAccount2 { public override string Role { get; set; } = "admin"; }

UserAccount2 u2 = new AdminAccount2();
Console.WriteLine(u2.Role); // prints 'admin' - correct

// ❌ BAD - all lambdas capture the same loop variable
var handlers = new List<Action>();
for (int i = 0; i < 3; i++)
    handlers.Add(() => Console.Write(i + " ")); // shared i
foreach (var h in handlers) h(); // prints 3 3 3

// ✅ GOOD - capture a per-iteration copy
var handlers2 = new List<Action>();
for (int i = 0; i < 3; i++) {
    int step = i; // new variable per iteration
    handlers2.Add(() => Console.Write(step + " "));
}
foreach (var h in handlers2) h(); // prints 0 1 2

// ❌ BAD - deferred query sees later mutations to the source
var productIds = new List<int> { 101, 102 };
var doubled = productIds.Select(id => id * 2); // not executed yet
productIds.Add(103);
foreach (var d in doubled) Console.Write(d + " "); // 202 204 206 - 103 included

// ✅ GOOD - materialize immediately to snapshot the current state
var productIds2 = new List<int> { 101, 102 };
var doubled2 = productIds2.Select(id => id * 2).ToList(); // runs now
productIds2.Add(103);
foreach (var d in doubled2) Console.Write(d + " "); // 202 204 - 103 excluded

// ❌ BAD - using == on boxed values expecting value comparison
object orderId1 = 1001;
object orderId2 = 1001;
if (orderId1 == orderId2) // False - different boxes
    Console.WriteLine("same order"); // never prints

// ✅ GOOD - use Equals for value comparison on boxed types
object orderId3 = 1001;
object orderId4 = 1001;
if (orderId3.Equals(orderId4)) // True - value comparison
    Console.WriteLine("same order"); // prints correctly

// ❌ BAD - using ReferenceEquals assuming runtime concat is interned
string host = "https://";
string endpoint = host + "api."; // runtime Concat - new object
string literal = "https://api.";
Console.WriteLine(object.ReferenceEquals(literal, endpoint)); // False - different objects

// ✅ GOOD - constant-folded literals are interned and share one object
string endpoint1 = "https://api.";
string endpoint2 = "https://" + "api."; // constant-folded at compile time
Console.WriteLine(object.ReferenceEquals(endpoint1, endpoint2)); // True

// ❌ BAD - unchecked overflow produces wrong balance silently
int accountBalance = int.MaxValue;
int deposit = 1;
int newBalance = accountBalance + deposit; // wraps to int.MinValue
Console.WriteLine(newBalance); // -2147483648 - account looks overdrawn

// ✅ GOOD - detect overflow with checked or use a larger type
long safeBalance = (long)int.MaxValue + 1;
Console.WriteLine(safeBalance); // 2147483648 - correct

// ❌ BAD - expecting all return values from a multicast Func
Func<decimal, decimal> applyTax = p => p * 1.1m; // returns 110
applyTax += p => p * 1.2m;                         // returns 120
applyTax += p => p * 1.3m;                         // returns 130
decimal price = applyTax(100m);
Console.WriteLine(price); // 130 - only last result kept, 110 and 120 lost

// ✅ GOOD - use GetInvocationList to collect all results
var results = applyTax.GetInvocationList()
    .Select(d => ((Func<decimal, decimal>)d)(100m));
foreach (var r in results) Console.Write(r + " "); // 110 120 130

// ❌ BAD - using (int) cast expecting rounding behavior
double itemPrice = 9.99;
int displayPrice = (int)itemPrice; // 9, not 10
Console.WriteLine("Price: " + displayPrice); // Price: 9 - wrong

// ✅ GOOD - use Math.Round when rounding is intended
int roundedPrice = (int)Math.Round(itemPrice); // 10
Console.WriteLine("Price: " + roundedPrice); // Price: 10 - correct

// ❌ BAD - assuming ?? also handles empty string or 0
string userId = null;
string displayName = null;
string label = userId ?? displayName ?? "Guest";
Console.WriteLine(label); // Guest - correct for null
// But: string empty = "" ?? "Guest" => "" (empty string is not null)

// ✅ GOOD - use ?? for null fallback, separate check for empty
string name = null;
string result = (string.IsNullOrEmpty(name) ? null : name) ?? "Guest";
Console.WriteLine(result); // Guest - handles both null and empty

// ❌ BAD - assuming code after the exception still runs in the try block
try {
    decimal rate = GetExchangeRate(); // throws if service is down
    decimal converted = amount * rate; // this line is skipped on exception
    Console.WriteLine(converted);      // this too - never reached
} catch (HttpRequestException) {
    Console.WriteLine("Service unavailable"); // runs
} finally {
    CloseConnection(); // always runs whether or not exception occurred
}

// ✅ GOOD - understand what runs and what is skipped
// Only lines before the throw execute in try. Finally is your cleanup guarantee.

// ❌ BAD - assuming outer catch runs before inner finally
try {
    try {
        decimal result = 100m / 0; // throws DivideByZeroException
    } finally {
        Console.WriteLine("Release database lock"); // runs FIRST during unwinding
    }
} catch {
    Console.WriteLine("Log to error tracking"); // runs SECOND
}
// Output: 'Release database lock' then 'Log to error tracking'

// ✅ GOOD - rely on this order for nested resource cleanup
// Inner finally = innermost resource cleanup first (LIFO order)

// ❌ BAD - assuming async runs all statements before the caller continues
async Task ProcessOrder(Order o) {
    Console.WriteLine("Validating"); // runs synchronously
    await SendEmailAsync(o);          // suspends here
    Console.WriteLine("Email sent"); // runs AFTER suspension resumes
}
var task = ProcessOrder(order);
Console.WriteLine("Order queued"); // runs WHILE email is being sent
// Output: Validating, Order queued, Email sent

// ✅ GOOD - use await or task.Wait() when you need the full sequence to complete
await ProcessOrder(order);
Console.WriteLine("Order queued"); // now runs AFTER email is sent

// ❌ BAD - assuming static ctor body runs before field initializers
// Many developers think 'Constructor' prints first

// ✅ GOOD - correct order: field initializer first, then static ctor body
class PaymentGateway {
    static string _provider = InitProvider(); // runs FIRST
    static PaymentGateway() {
        Console.WriteLine("Gateway ready"); // runs SECOND
    }
    static string InitProvider() {
        Console.WriteLine("Provider loaded");
        return "Stripe";
    }
}
string p = PaymentGateway._provider;
// Output: 'Provider loaded' then 'Gateway ready'

// ❌ BAD - no null guard on params array
void SendAlerts(params string[] recipients) {
    Console.WriteLine(recipients.Length); // NRE if null is passed
}
SendAlerts();       // 0 - safe (empty array)
SendAlerts(null);   // NullReferenceException

// ✅ GOOD - guard against null
void SendAlerts2(params string[] recipients) {
    int count = recipients?.Length ?? 0;
    Console.WriteLine(count); // 0 for both no-args and null
}

// ❌ BAD - trying to use List<Dog> where List<Animal> expected
class Animal {} class Dog : Animal {}
List<Dog> dogs = new List<Dog> { new Dog() };
// List<Animal> animals = dogs; // compile error - List is invariant

// ✅ GOOD - IEnumerable is covariant, so this works
IEnumerable<Dog> dogSeq = new List<Dog> { new Dog() };
IEnumerable<Animal> animalSeq = dogSeq; // covariance - OK
Console.WriteLine(animalSeq.Count()); // 1 - same sequence enumerated

// ❌ BAD - assuming struct fields need explicit initialization
struct ProductSpec { public string Description; public int Weight; }
ProductSpec spec = new ProductSpec();
// Reading spec.Description without checking null could NRE
Console.WriteLine(spec.Description.Length); // NullReferenceException

// ✅ GOOD - always check reference fields in a struct for null
struct ProductSpec2 { public string Description; public int Weight; }
ProductSpec2 spec2 = new ProductSpec2();
Console.WriteLine(spec2.Description == null); // True - zero-initialized
Console.WriteLine(spec2.Weight);               // 0 - zero-initialized

// ❌ BAD - forgetting ToList, later mutation changes results
var orders = new List<Order> { new Order(1), new Order(2) };
var activeOrders = orders.Where(o => o.IsActive); // deferred
orders.Add(new Order(3)); // added after query defined
Console.WriteLine(activeOrders.Count()); // includes order 3 - unexpected

// ✅ GOOD - ToList snapshots at the right moment
var activeOrdersSnapshot = orders.Where(o => o.IsActive).ToList();
orders.Add(new Order(3));
Console.WriteLine(activeOrdersSnapshot.Count); // excludes order 3 - correct

// ❌ BAD - expecting the caller's value to change without ref
void ApplyDiscount(decimal price) { price *= 0.9m; } // mutates copy only
decimal subtotal = 100m;
ApplyDiscount(subtotal);
Console.WriteLine(subtotal); // 100 - discount never applied

// ✅ GOOD - ref passes the actual variable
void ApplyDiscount2(ref decimal price) { price *= 0.9m; }
decimal subtotal2 = 100m;
ApplyDiscount2(ref subtotal2);
Console.WriteLine(subtotal2); // 90 - discount applied to caller's variable

// ❌ BAD - exception in one handler blocks remaining handlers
Action onOrderPlaced = () => SendConfirmationEmail();  // handler 1
onOrderPlaced += () => throw new Exception("SMS failed"); // handler 2
onOrderPlaced += () => UpdateInventory();               // handler 3 - NEVER RUNS
try { onOrderPlaced(); } catch { /* only SMS exception caught */ }

// ✅ GOOD - isolate each handler so failures don't cascade
foreach (Action handler in onOrderPlaced.GetInvocationList()) {
    try { handler(); }
    catch (Exception ex) { _logger.LogError(ex, "Handler failed"); }
}

// ❌ BAD - non-virtual, declared type wins
class Carrier { public void Ship(Order o) => Console.WriteLine("default ship"); }
class DhlCarrier : Carrier { public void Ship(Order o) => Console.WriteLine("DHL"); }

Carrier c = new DhlCarrier();
c.Ship(order); // 'default ship' - wrong

// ✅ GOOD - virtual+override, runtime type wins
class Carrier2 { public virtual void Ship(Order o) => Console.WriteLine("default ship"); }
class DhlCarrier2 : Carrier2 { public override void Ship(Order o) => Console.WriteLine("DHL"); }

Carrier2 c2 = new DhlCarrier2();
c2.Ship(order); // 'DHL' - correct

// ❌ BAD - treating a class like a struct (expecting independence)
class Coordinate { public int X; }
Coordinate origin = new Coordinate { X = 0 };
Coordinate copy = origin; // only copies the reference
copy.X = 99;
Console.WriteLine(origin.X); // 99 - NOT 0, shared object mutated

// ✅ GOOD - struct gives true independence
struct CoordinateStruct { public int X; }
CoordinateStruct s1 = new CoordinateStruct { X = 0 };
CoordinateStruct s2 = s1; // full field copy
s2.X = 99;
Console.WriteLine(s1.X); // 0 - unchanged

// ❌ BAD - expecting struct mutation to affect the caller
struct Inventory { public int Stock; }
void Restock(Inventory inv) { inv.Stock += 100; } // mutates copy
Inventory warehouse = new Inventory { Stock = 50 };
Restock(warehouse);
Console.WriteLine(warehouse.Stock); // 50 - unchanged

// ✅ GOOD - use ref to mutate the caller's struct
void Restock2(ref Inventory inv) { inv.Stock += 100; }
Inventory warehouse2 = new Inventory { Stock = 50 };
Restock2(ref warehouse2);
Console.WriteLine(warehouse2.Stock); // 150 - correct

// ❌ BAD - missing ref, mutation is lost
struct Inventory { public int Stock; }
void DecrementStock(Inventory inv) { inv.Stock--; } // mutates copy
Inventory item = new Inventory { Stock = 5 };
DecrementStock(item);
Console.WriteLine(item.Stock); // 5 - copy was decremented, not original

// ✅ GOOD - ref passes the address
void DecrementStock2(ref Inventory inv) { inv.Stock--; }
Inventory item2 = new Inventory { Stock = 5 };
DecrementStock2(ref item2);
Console.WriteLine(item2.Stock); // 4 - original decremented correctly

// ❌ BAD - compile error: cannot modify return value of List indexer
struct Waypoint { public int X; }
var route = new List<Waypoint> { new Waypoint { X = 10 } };
// CS1612: Cannot modify the return value of 'List<Waypoint>.this[int]'
// because it is not a variable
route[0].X = 99; // compile error

// ✅ GOOD - extract, modify, put back
var wp = route[0]; // copy out
wp.X = 99;         // mutate copy
route[0] = wp;     // put back via the set accessor

// ❌ BAD - confusing array with List for struct mutation
struct Sensor { public float Temperature; }
var readings = new List<Sensor> { new Sensor { Temperature = 36.5f } };
// readings[0].Temperature = 37.0f; // CS1612 - compile error

// ✅ GOOD - arrays allow direct mutation
Sensor[] sensorArray = { new Sensor { Temperature = 36.5f } };
sensorArray[0].Temperature = 37.0f; // legal - direct write to element storage
Console.WriteLine(sensorArray[0].Temperature); // 37

// ❌ BAD - calling mutating method on readonly field, mutation is silently lost
struct PricePoint { public decimal Value; public void Adjust(decimal d) { Value += d; } }
class Product {
    public readonly PricePoint BasePrice = new PricePoint { Value = 100m };
}
var p = new Product();
p.BasePrice.Adjust(10m); // defensive copy - BasePrice unchanged
Console.WriteLine(p.BasePrice.Value); // 100 - NOT 110

// ✅ GOOD - readonly struct eliminates defensive copies
readonly struct PricePoint2 { public decimal Value { get; init; } }
// Adjust() cannot exist as non-readonly - compiler enforces immutability

// ❌ BAD - expecting unbox-mutate to change the box or the original
struct StockLevel { public int Quantity; }
StockLevel level = new StockLevel { Quantity = 100 };
object boxed = level; // boxes a copy
((StockLevel)boxed).Quantity = 0; // unboxes to temp, mutates temp, temp discarded
Console.WriteLine(level.Quantity);               // 100 - original unchanged
Console.WriteLine(((StockLevel)boxed).Quantity); // 100 - box unchanged

// ✅ GOOD - unbox, mutate, rebox to change the boxed value
StockLevel temp = (StockLevel)boxed;
temp.Quantity = 0;
boxed = temp; // rebox the mutated copy
Console.WriteLine(((StockLevel)boxed).Quantity); // 0 - correct

// ❌ BAD - mutable struct assigned to interface, state splits
interface IBalance { void Deposit(decimal amount); decimal Amount { get; } }
struct Account : IBalance {
    private decimal _amount;
    public decimal Amount => _amount;
    public void Deposit(decimal amount) { _amount += amount; }
}
Account acct = new Account();
IBalance ib = acct; // boxes a copy
ib.Deposit(100m);   // increments the boxed copy
Console.WriteLine(acct.Amount); // 0 - original unchanged
Console.WriteLine(ib.Amount);   // 100 - boxed copy changed

// ✅ GOOD - use a class for mutable types that implement interfaces
class Account2 : IBalance { /* ... */ }

// ❌ BAD - assuming struct copy gives independence for reference-type fields
struct CustomerData { public string[] Tags; }
CustomerData customer = new CustomerData { Tags = new[] { "premium" } };
CustomerData backup = customer; // shallow copy - Tags pointers are shared
backup.Tags[0] = "basic"; // mutates the shared array
Console.WriteLine(customer.Tags[0]); // 'basic' - original changed too

// ✅ GOOD - deep copy the reference-type field
CustomerData deepBackup = new CustomerData { Tags = (string[])customer.Tags.Clone() };
deepBackup.Tags[0] = "basic";
Console.WriteLine(customer.Tags[0]); // 'premium' - original safe

// ❌ BAD - compile error trying to mutate foreach struct variable
struct Product { public decimal Price; }
var catalog = new List<Product> { new Product { Price = 10m }, new Product { Price = 20m } };
foreach (var p in catalog) {
    // CS1654: Cannot assign to members of 'p'
    p.Price *= 1.1m; // compile error
}

// ✅ GOOD - for loop with extract-modify-replace
for (int i = 0; i < catalog.Count; i++) {
    var p = catalog[i];
    p.Price *= 1.1m;
    catalog[i] = p;
}

// ❌ BAD - mutable struct in readonly field: hidden defensive copies on every call
struct Bounds { public float MinX; public float Width; public float MaxX() => MinX + Width; }
class Scene { public readonly Bounds Area = new Bounds { MinX = 0, Width = 100 }; }
var scene = new Scene();
Console.WriteLine(scene.Area.MaxX()); // defensive copy on every call

// ✅ GOOD - readonly struct: no defensive copy, same result, better performance
readonly struct Bounds2 {
    public float MinX { get; init; }
    public float Width { get; init; }
    public float MaxX() => MinX + Width; // safe - no mutation possible
}
class Scene2 { public readonly Bounds2 Area = new Bounds2 { MinX = 0, Width = 100 }; }
Console.WriteLine(new Scene2().Area.MaxX()); // direct read, no copy

// ❌ BAD - plain struct has no == operator
struct GpsCoord { public double Lat; public double Lon; }
GpsCoord a = new GpsCoord { Lat = 51.5, Lon = -0.1 };
GpsCoord b = new GpsCoord { Lat = 51.5, Lon = -0.1 };
// Console.WriteLine(a == b); // CS0019 - compile error
Console.WriteLine(a.Equals(b)); // True but reflection-based and slow

// ✅ GOOD - record struct synthesizes all equality members
record struct GpsCoord2(double Lat, double Lon);
GpsCoord2 c = new GpsCoord2(51.5, -0.1);
GpsCoord2 d = new GpsCoord2(51.5, -0.1);
Console.WriteLine(c == d);      // True - synthesized
Console.WriteLine(c.Equals(d)); // True - strongly typed

// ❌ BAD - plain struct, == does not compile
struct OrderKey { public int OrderId; public string Region; }
OrderKey k1 = new OrderKey { OrderId = 1, Region = "EU" };
OrderKey k2 = new OrderKey { OrderId = 1, Region = "EU" };
// Console.WriteLine(k1 == k2); // CS0019 - compile error

// ✅ GOOD option 1 - overload == manually
public static bool operator ==(OrderKey l, OrderKey r) =>
    l.OrderId == r.OrderId && l.Region == r.Region;
public static bool operator !=(OrderKey l, OrderKey r) => !(l == r);
// override Equals and GetHashCode too

// ✅ GOOD option 2 - use record struct (synthesized for free)
record struct OrderKey2(int OrderId, string Region);

// ❌ BAD - traditional approach: heap allocation for a small temporary buffer
byte[] buffer = new byte[256]; // heap allocation, GC pressure
ProcessRequest(data, buffer);

// ✅ GOOD - stack allocation with Span<byte>: zero heap allocation
Span<byte> stackBuffer = stackalloc byte[256];
ProcessRequest(data, stackBuffer);
// stackBuffer is freed when this scope exits - no GC needed

// Safe stackalloc - no unsafe block required
Span<int> prices = stackalloc int[3] { 100, 200, 300 };
int total = 0;
foreach (var p in prices) total += p;
Console.WriteLine(total); // 600

// ❌ BAD - expecting LINQ to mutate the original list elements
struct LineItem { public decimal Price; }
var cart = new List<LineItem> { new LineItem { Price = 100m } };
var discounted = cart.Select(item => { item.Price *= 0.9m; return item; }).ToList();
Console.WriteLine(cart[0].Price);       // 100 - original unchanged
Console.WriteLine(discounted[0].Price); // 90 - only pipeline copy changed

// ✅ GOOD - use for loop to update the original list
for (int i = 0; i < cart.Count; i++) {
    var item = cart[i];
    item.Price *= 0.9m;
    cart[i] = item;
}
Console.WriteLine(cart[0].Price); // 90 - correct
